#include <bits/stdc++.h>
using namespace std;
int main() {
	int V, E;
	cin >> V >> E;
	vector<vector<int>> graph(V);
	for (int i = 0; i < E; i++) {
		int u, v;
		cin >> u >> v;
		graph[u].push_back(v);
		graph[v].push_back(u);
	}
	int S;
	cin >> S;
	vector<bool> visited(V, false);
	queue<int> q;
	q.push(S);
	visited[S] = true;
	while (!q.empty()) {
		int vertex = q.front();
		q.pop();
		cout << vertex << '\n';
		for (int neighbor : graph[vertex]) {
			if (!visited[neighbor]) {
				q.push(neighbor);
				visited[neighbor] = true;
			}
		}
	}
	return 0;
}
